// ── Collect all 4 inputs ──
const all = $input.all().map(i => i.json);
const pmRows   = all.filter(r => r.RiskVerdict  !== undefined);
const eodRows  = all.filter(r => r.SPY_Close    !== undefined);
const econRows = all.filter(r => r.Event        !== undefined);
const newsRows = all.filter(r => r.headline     !== undefined);

// ── Week date range (Mon–Fri of current week) ──
const now = new Date();
const day = now.getDay(); // 0=Sun
const monday = new Date(now);
monday.setDate(now.getDate() - (day === 0 ? 6 : day - 1));
monday.setHours(0,0,0,0);
const friday = new Date(monday);
friday.setDate(monday.getDate() + 4);
friday.setHours(23,59,59,999);

// FIX 3: Partial week flag — true if run before Friday close
const isPartialWeek = day !== 5 && day !== 6; // not Fri/Sat
const dayNames = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
const weekStatus = isPartialWeek
  ? `PARTIAL — run on ${dayNames[day]}, auto-posts Friday 5PM ET`
  : 'COMPLETE';

// ── Robust date parser ──
const parseDate = raw => {
  if (!raw) return null;
  const s = String(raw).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return new Date(s + 'T12:00:00Z');
  if (/^\d{4}-\d{2}-\d{2}T/.test(s)) return new Date(s);
  const d = new Date(s);
  if (!isNaN(d)) return d;
  if (s.includes('/')) {
    const p = s.split('/');
    return new Date(parseInt(p[2]), parseInt(p[0])-1, parseInt(p[1]), 12, 0, 0);
  }
  return null;
};

const inThisWeek = raw => { const d = parseDate(raw); return d && d >= monday && d <= friday; };

const sortByDate = arr => [...arr].sort((a,b) => {
  const da = parseDate(a.Date || a.date || a.Timestamp) || 0;
  const db = parseDate(b.Date || b.date || b.Timestamp) || 0;
  return da - db;
});

const getRowDate = r => r.Date || (r.Timestamp ? r.Timestamp.split('T')[0] : null);

// FIX 1: Deduplicate by date — keep last (most recent) row per date
const dedup = arr => {
  const seen = {};
  return arr.slice().reverse().filter(r => {
    const key = String(getRowDate(r) || '').substring(0,10);
    if (!key || seen[key]) return false;
    seen[key] = true;
    return true;
  }).reverse();
};

const pm   = dedup(sortByDate(pmRows.filter(r  => inThisWeek(getRowDate(r)))));
const eod  = dedup(sortByDate(eodRows.filter(r => inThisWeek(getRowDate(r)))));
const econ = econRows.filter(r => r['Log Mode'] === 'daily' && inThisWeek(r.Date));
const news = newsRows.filter(r => inThisWeek(r.date));

console.log(`PM rows: ${pm.length}, EOD rows: ${eod.length}, Econ: ${econ.length}, News: ${news.length} | Week status: ${weekStatus}`);

// ── Next-week econ preview (FIX 9) ──
const nextMonday = new Date(monday); nextMonday.setDate(monday.getDate() + 7);
const nextFriday = new Date(friday); nextFriday.setDate(friday.getDate() + 7);
const inNextWeek = raw => { const d = parseDate(raw); return d && d >= nextMonday && d <= nextFriday; };
const nextWeekEcon = econRows.filter(r =>
  (r['Log Mode'] === 'weekly_preview' || r['Log Mode'] === 'daily') && inNextWeek(r.Date)
);
const nextWeekLabel = nextMonday.toLocaleDateString('en-US',{month:'short',day:'numeric'}) +
  ' – ' + nextFriday.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'});
const nextEconSummary = nextWeekEcon.length
  ? nextWeekEcon.map(r =>
      (((r.Impact||'').toLowerCase()==='high') ? '🔴' : '🟡') +
      ' ' + r.Event + ' — Fcst: '+(r.Forecast||'N/A')+' | Prev: '+(r.Previous||'N/A')
    ).join('\n')
  : 'No high/medium impact events on the calendar.';

// ── Helpers ──
const toF  = v => { const n = parseFloat(v); return isNaN(n) ? null : n; };
const r2   = v => { const n = toF(v); return n === null ? null : Math.round(n*100)/100; };
const sign = v => (toF(v) || 0) >= 0 ? '+' : '';
const pct  = v => { const n = r2(v); return n === null ? 'N/A' : sign(n) + n + '%'; };
const shortDate = d => {
  const s = String(d||'');
  const parts = s.split(',');
  if (parts.length >= 3) {
    const dayAbbr = parts[0].trim().substring(0,3);
    const md = parts[1].trim().split(' ');
    const months = {January:'1',February:'2',March:'3',April:'4',May:'5',June:'6',July:'7',August:'8',September:'9',October:'10',November:'11',December:'12'};
    return dayAbbr + ' ' + (months[md[0]]||md[0]) + '/' + md[1];
  }
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) {
    const d = new Date(s + 'T12:00:00Z');
    return ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'][d.getUTCDay()] + ' ' + (d.getUTCMonth()+1) + '/' + d.getUTCDate();
  }
  return s.substring(0,10);
};

const weekLabel = monday.toLocaleDateString('en-US',{month:'short',day:'numeric'}) +
  ' – ' + friday.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'});

// ── Risk (FIX 2: include full verdict text in daily risk block) ──
const verdictEmoji = v => {
  const s = (v||'').toLowerCase();
  if (s.includes('risk-on') && !s.includes('lean')) return '🟢';
  if (s.includes('lean') && s.includes('risk-on')) return '🟡';
  if (s.includes('neutral')) return '⚪';
  if (s.includes('lean') && s.includes('risk-off')) return '🟠';
  if (s.includes('risk-off')) return '🔴';
  return '⚪';
};
const riskScores  = pm.map(r => parseInt(r.RiskScore)).filter(v => !isNaN(v));
const riskTrend   = riskScores.length >= 2
  ? (riskScores.at(-1) > riskScores[0] ? 'Improving' : riskScores.at(-1) < riskScores[0] ? 'Deteriorating' : 'Stable')
  : 'N/A';
const verdicts    = pm.map(r => r.RiskVerdict).filter(Boolean);
const verdictCount = verdicts.reduce((a,v)=>{a[v]=(a[v]||0)+1;return a;},{});
const dominantVerdict = Object.entries(verdictCount).sort((a,b)=>b[1]-a[1])[0]?.[0] || 'N/A';

// FIX 2: full verdict label with emoji in data block
const dailyRisk = pm.map(r =>
  shortDate(r.Date) + ': ' + verdictEmoji(r.RiskVerdict) + ' ' + (r.RiskVerdict||'N/A') +
  ' | Score: ' + (r.RiskScore||'N/A') +
  (r.VIX ? ' | VIX: ' + r.VIX : '') +
  (r.RiskFactors ? ' — ' + r.RiskFactors : '')
).join('\n');

const vixVals = [...pm.map(r=>toF(r.VIX)), ...eod.map(r=>toF(r.VIX_Close))].filter(v=>v!==null&&v>0);
const vixHigh = vixVals.length ? Math.max(...vixVals).toFixed(2) : 'N/A';
const vixLow  = vixVals.length ? Math.min(...vixVals).toFixed(2) : 'N/A';
const vixAvg  = vixVals.length ? (vixVals.reduce((a,b)=>a+b,0)/vixVals.length).toFixed(2) : 'N/A';
const regimes = [...new Set(pm.map(r=>r.Regime).filter(Boolean))].join(', ');

// ── Market performance (FIX 4: week-to-date label) ──
const spyStart = pm[0]      ? toF(pm[0].SPY_Price)      : null;
const spyEnd   = eod.at(-1) ? toF(eod.at(-1).SPY_Close) : null;
const spyWeekVal = spyStart && spyEnd ? (((spyEnd-spyStart)/spyStart)*100).toFixed(2) : null;
const spyWeekStr = spyWeekVal !== null
  ? (isPartialWeek ? `${pct(spyWeekVal)} week-to-date` : pct(spyWeekVal))
  : 'N/A';
const dailyMoves = eod.map(r =>
  shortDate(r.Date) + ': SPY ' + pct(r.SPY_Change) + ' | QQQ ' + pct(r.QQQ_Change) + ' | IWM ' + pct(r.IWM_Change)
).join('\n');
const yieldEnd   = eod.at(-1) ? toF(eod.at(-1).Yield10Y) : null;
const yieldStart = pm[0]      ? toF(pm[0].Yield10Y)       : null;
const yieldChg   = yieldStart !== null && yieldEnd !== null ? (yieldEnd - yieldStart).toFixed(3) : 'N/A';
const wkAvg = arr => arr.length ? (arr.reduce((a,b)=>a+b,0)/arr.length).toFixed(2) : 'N/A';
const goldAvg = wkAvg(eod.map(r=>toF(r.Gold_Change)).filter(v=>v!==null));
const oilAvg  = wkAvg(eod.map(r=>toF(r.Oil_Change)).filter(v=>v!==null));
const btcAvg  = wkAvg(eod.map(r=>toF(r.BTC_Change)).filter(v=>v!==null));
const dxyAvg  = wkAvg(eod.map(r=>toF(r.DXY_Change)).filter(v=>v!==null));

// ── Sectors ──
const sectors = ['XLK','XLY','XLF','XLI','XLB','XLE','XLV','XLU','XLRE','XLP','XLC'];
const sectorNames = {XLK:'Tech',XLY:'Cons Disc',XLF:'Financials',XLI:'Industrials',XLB:'Materials',XLE:'Energy',XLV:'Healthcare',XLU:'Utilities',XLRE:'Real Estate',XLP:'Cons Staples',XLC:'Comm Svcs'};
const sectorTotals = {};
sectors.forEach(s => {
  const vals = eod.map(r=>toF(r[s+'_Change'])).filter(v=>v!==null);
  sectorTotals[s] = vals.length ? vals.reduce((a,b)=>a+b,0) : null;
});
const rankedSectors = Object.entries(sectorTotals).filter(([,v])=>v!==null).sort((a,b)=>b[1]-a[1]);
const sectorSummary = rankedSectors.map(([s,v]) => s+'('+sectorNames[s]+'): '+pct(v)).join(', ');
const topSector = rankedSectors[0]     ? rankedSectors[0][0]     + ' (' + sectorNames[rankedSectors[0][0]]     + ')' : 'N/A';
const botSector = rankedSectors.at(-1) ? rankedSectors.at(-1)[0] + ' (' + sectorNames[rankedSectors.at(-1)[0]] + ')' : 'N/A';
const rotBias   = [...new Set(eod.map(r=>r.RotationBias).filter(Boolean))].join(', ');
const focusSecs = [...new Set(pm.map(r=>r.FocusSectors).filter(Boolean))].join(' / ');

// ── Futures & breadth ──
const futuresSummary = pm.map(r =>
  shortDate(r.Date) + ': ES ' + pct(r.ES_Change) + ' | NQ ' + pct(r.NQ_Change)
).join('\n');
const breadthSummary = eod.map(r =>
  shortDate(r.Date) + ': ' + (r.BreadthClose||'N/A') + ' | Credit: ' + (r.CreditClose||'N/A')
).join('\n');
const unusualAll  = eod.flatMap(r=>(r.UnusualMovers||'').split(',').map(s=>s.trim())).filter(Boolean);
const unusualFreq = unusualAll.reduce((a,v)=>{a[v]=(a[v]||0)+1;return a;},{});
const topUnusual  = Object.entries(unusualFreq).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([k,v])=>k+(v>1?' ('+v+'d)':'')).join(', ');

// ── Econ events (this week) ──
const econHigh = econ.filter(r=>(r.Impact||'').toLowerCase()==='high');
const econMed  = econ.filter(r=>(r.Impact||'').toLowerCase()==='medium');
const econSummary = [...econHigh,...econMed].map(r =>
  r.Event + ' — Fcst: '+(r.Forecast||'N/A')+' | Act: '+(r.Actual||'pending')+' | Prev: '+(r.Previous||'N/A')
).join('\n');

// ── News ──
const catGroups = {};
news.forEach(r => { const c=(r.category||'general').toLowerCase(); if(!catGroups[c])catGroups[c]=[]; catGroups[c].push(r); });
const newsSummary = Object.entries(catGroups).map(([cat,items]) =>
  cat.toUpperCase() + ' (' + items.length + ' stories):\n' +
  items.slice(-4).map(r => '  • ' + r.headline).join('\n')
).join('\n\n');

// ── Full data block ──
const dataBlock = `WEEK OF: ${weekLabel} [${weekStatus}]

=== RISK ENVIRONMENT ===
Dominant Tone: ${dominantVerdict} | Trend: ${riskTrend} | VIX: ${vixLow}–${vixHigh} (avg ${vixAvg}) | Regime: ${regimes}
Daily Risk (emoji + full label + score + VIX):
${dailyRisk || 'No pre-market data'}

=== MARKET PERFORMANCE ===
SPY: ${spyWeekStr} (closed ${spyEnd !== null ? spyEnd.toFixed(2) : 'N/A'})
Daily Moves (EOD):
${dailyMoves || 'No EOD data'}
10Y Yield: ${yieldEnd !== null ? yieldEnd+'%' : 'N/A'} (week chg: ${yieldChg !== 'N/A' ? (parseFloat(yieldChg)>=0?'+':'')+yieldChg+'bps' : 'N/A'})
Gold avg: ${pct(goldAvg)} | Oil: ${pct(oilAvg)} | BTC: ${pct(btcAvg)} | DXY: ${pct(dxyAvg)}

=== SECTOR ROTATION ===
Top Sector: ${topSector} | Bottom: ${botSector}
Rotation Bias: ${rotBias || 'N/A'} | Pre-Market Focus: ${focusSecs || 'N/A'}
Full Ranking: ${sectorSummary || 'No EOD sector data'}

=== FUTURES & BREADTH ===
Pre-Market Futures:
${futuresSummary || 'No pre-market data'}
Breadth & Credit (EOD):
${breadthSummary || 'No EOD data'}
Unusual Volume Movers: ${topUnusual || 'None flagged'}

=== KEY ECONOMIC EVENTS (THIS WEEK) ===
${econSummary || 'No high/medium impact events logged this week.'}

=== NEXT WEEK CALENDAR (${nextWeekLabel}) ===
${nextEconSummary}

=== NEWS THEMES ===
${newsSummary || 'No news logged this week.'}`;

return [{ json: { dataBlock, weekLabel, isPartialWeek, weekStatus, nextWeekLabel } }];

// LLM chain nodes output { text: '...' }
const discordRaw  = $('Groq Discord Version').first().json?.text || '';
const substackRaw = $('Groq Substack Version').first().json?.text || '';
const { weekLabel } = $('Build Prompts').first().json;

// Split discord into chunks on ---MSG_BREAK---
const discordChunks = discordRaw.split('---MSG_BREAK---').map(s => s.trim()).filter(Boolean);

// Ensure max 3 chunks, each under 1900 chars
const safeChunks = discordChunks.slice(0, 3).map(chunk =>
  chunk.length > 1900 ? chunk.substring(0, 1897) + '...' : chunk
);

const discordMsg1 = safeChunks[0] || '_(no content)_';
const discordMsg2 = safeChunks[1] || '';
const discordMsg3 = safeChunks[2] || '';

const now = new Date().toISOString();

return [{ json: {
  weekLabel,
  discordMsg1,
  discordMsg2,
  discordMsg3,
  discordFull: discordRaw,
  substackFull: substackRaw,
  generatedAt: now
}}];
